/* Shared "Model Edge vs Polymarket // Advancement" matrix.
 *
 * Single source of truth for both Scores (scores.js) and Visuals (visuals.js)
 * so the two pages can never drift. Renders the live edge⇄kelly matrix from
 * advancement_data.json into a target element.
 *
 * Usage:  window.WCAEdgeMatrix("adv-edge", advancementData)
 *
 * The data is regenerated by scripts/wca_advancement_data.py (published with the
 * site), so the table reflects current model-vs-market state — never a snapshot.
 */
(function () {
  "use strict";

  function esc(v) {
    if (v === null || v === undefined) return "";
    return String(v).replace(/&/g, "&amp;").replace(/</g, "&lt;")
      .replace(/>/g, "&gt;").replace(/"/g, "&quot;").replace(/'/g, "&#39;");
  }

  // Cell mode: "edge" (raw fee-adjusted edge, points) or "kelly" (recommended
  // stake). Module-scoped so the toggle sticks across re-renders within a page.
  var EDGE_MODE = "edge";

  // Polymarket advancement sizing — mirrors src/wca/advancement.py
  // (PM_KELLY_FRACTION, PM_PER_BET_CAP, PM_POOL_BANKROLL) and the
  // fractional-Kelly + cap in src/wca/markets/kelly.py.
  var PM_KELLY_FRAC = 0.25, PM_CAP = 0.05, PM_POOL = 1310;

  // Quarter-Kelly stake (fraction of the $1,310 PM pool, capped at 5%) for the
  // value side of a team's advancement market, sized off the feed's `edge_adj`
  // — the proposer's fee- AND spread-adjusted edge for the side it would take,
  // measured against the real executable buy price (not the mid). We reuse
  // edge_adj instead of recomputing from the mid so the stake matches what the
  // bot actually proposes and stays consistent with the edge view. model = our
  // probability; pm = mid price, used only to pick the side (back/buy-Yes when
  // model > mid, fade/buy-No when model < mid). With sideProb the win prob of
  // the side bought, the executable cost = sideProb - edge_adj and full Kelly =
  // edge_adj / (1 - cost) = (p*o - 1)/(o - 1) with o = 1/cost. Returns
  // { side: "back"|"fade"|null, frac }; frac is 0 when edge_adj <= 0 (fees +
  // spread erase the edge, so the bot would place no bet).
  function advKelly(model, pm, edgeAdj) {
    if (model == null || pm == null || edgeAdj == null) return { side: null, frac: 0 };
    var ea = Number(edgeAdj);
    if (ea <= 0) return { side: null, frac: 0 };
    var m = Number(model);
    var side = (m >= Number(pm)) ? "back" : "fade";
    var sideProb = (side === "back") ? m : (1 - m);   // win prob of the side bought
    var cost = sideProb - ea;                          // executable cost baked into edge_adj
    if (cost <= 0 || cost >= 1) return { side: side, frac: 0 };
    var full = ea / (1 - cost);
    if (full <= 0) return { side: side, frac: 0 };
    return { side: side, frac: Math.min(full * PM_KELLY_FRAC, PM_CAP) };
  }

  function render(elId, d) {
    var el = document.getElementById(elId);
    if (!el || !d) return;
    var teams = (d.teams || []).filter(function (t) {
      return t.model && (Number(t.model.win) || 0) > 0.003;
    });
    teams.sort(function (a, b) { return (Number(b.model.win) || 0) - (Number(a.model.win) || 0); });
    teams = teams.slice(0, 18);
    if (!teams.length) { el.innerHTML = '<div class="empty">No advancement data yet</div>'; return; }
    var stages = [["group_winner", "Grp"], ["R32", "R32"], ["R16", "R16"], ["QF", "QF"],
                  ["SF", "SF"], ["Final", "Final"], ["win", "Win"]];
    var kellyMode = EDGE_MODE === "kelly";
    function bg(v) {
      if (v === null) return "transparent";
      var a = Math.min(1, Math.abs(v) / 0.15) * 0.8 + 0.06;
      return (v >= 0 ? "rgba(63,224,138," : "rgba(224,96,63,") + a.toFixed(2) + ")";
    }
    function kbg(side, frac) {
      if (!side) return "transparent";
      var a = Math.min(1, frac / PM_CAP) * 0.8 + 0.06;
      return (side === "back" ? "rgba(63,224,138," : "rgba(224,96,63,") + a.toFixed(2) + ")";
    }
    var toggle = '<div class="adv-edge-toggle">' +
      '<button type="button" class="adv-emode' + (kellyMode ? "" : " on") + '" data-mode="edge">edge</button>' +
      '<button type="button" class="adv-emode' + (kellyMode ? " on" : "") + '" data-mode="kelly">kelly</button></div>';
    var legCells = kellyMode
      ? '<span><span class="d" style="background:rgba(63,224,138,0.85)"></span>back &mdash; buy Yes (model &gt; market)</span>' +
        '<span><span class="d" style="background:rgba(224,96,63,0.85)"></span>fade &mdash; buy No (model &lt; market)</span>' +
        '<span style="color:var(--muted)">cells: &frac14;-Kelly stake, % of $1,310 pool &middot; fee-adj &middot; capped 5% &middot; hover for $</span>'
      : '<span><span class="d" style="background:rgba(63,224,138,0.85)"></span>model above market &mdash; back</span>' +
        '<span><span class="d" style="background:rgba(224,96,63,0.85)"></span>model below market &mdash; fade</span>' +
        '<span style="color:var(--muted)">cells: edge in points &middot; intensity = size</span>';
    var leg = '<div class="adv-edge-leg">' + legCells + "</div>";
    var cols = "132px repeat(" + stages.length + ", 1fr)";
    var h = '<div class="adv-edge-grid" style="grid-template-columns:' + cols + '"><div></div>';
    stages.forEach(function (s) { h += '<div class="eh">' + s[1] + "</div>"; });
    teams.forEach(function (t) {
      h += '<div class="et">' + esc(t.team) + "</div>";
      stages.forEach(function (s) {
        var pmObj = t.pm ? t.pm[s[0]] : null;
        var cbg, txt, title;
        if (kellyMode) {
          var q = (pmObj && pmObj.pm != null) ? Number(pmObj.pm) : null;
          var p = (t.model && t.model[s[0]] != null) ? Number(t.model[s[0]]) : null;
          var ea = (pmObj && pmObj.edge_adj != null) ? Number(pmObj.edge_adj) : null;
          var k = advKelly(p, q, ea);
          if (!k.side) {
            txt = '<span style="color:var(--muted)">&middot;</span>';
            cbg = "transparent";
            title = (q == null) ? "no PM market" : "no edge beyond the fee";
          } else {
            txt = (k.frac * 100).toFixed(1);
            cbg = kbg(k.side, k.frac);
            title = k.side + " " + (k.frac * 100).toFixed(1) + "% of pool = $" +
              (k.frac * PM_POOL).toFixed(0) + " (¼-Kelly, capped 5%)";
          }
        } else {
          var v = (pmObj && pmObj.edge_adj != null) ? Number(pmObj.edge_adj) : null;
          txt = v === null ? '<span style="color:var(--muted)">&middot;</span>'
            : (v >= 0 ? "+" : "") + (v * 100).toFixed(1);
          cbg = bg(v);
          title = (v === null) ? "no PM market"
            : "fee-adj edge " + (v >= 0 ? "+" : "") + (v * 100).toFixed(1) + " pts";
        }
        h += '<div class="ec" style="background:' + cbg + '" title="' +
          esc(t.team + " · " + s[1] + " — " + title) + '">' + txt + "</div>";
      });
    });
    h += "</div>";
    el.innerHTML = toggle + leg + '<div class="adv-edge-wrap">' + h + "</div>";
    Array.prototype.forEach.call(el.querySelectorAll(".adv-emode"), function (btn) {
      btn.addEventListener("click", function () {
        var m = btn.getAttribute("data-mode");
        if (m === EDGE_MODE) return;
        EDGE_MODE = m;
        render(elId, d);
      });
    });
  }

  window.WCAEdgeMatrix = render;
})();
